# ===== changeling/__init__.py =====
"""changeling — breeding transferable in-context learners. See SPEC.md."""

OBS_DIM = 64
N_ACT = 8
IN_DIM = OBS_DIM + N_ACT + 2  # obs, onehot(last action), last reward, boundary bit

# ===== changeling/envs.py =====
"""Phase 0 environments in pure JAX.

An env is a dict of pure functions sharing the fixed interface protocol
(SPEC section 2): obs padded to OBS_DIM, actions in [0, N_ACT).

  sample_task(key) -> task            (per-lifetime parameters)
  reset(key, task) -> (state, obs)    (per-episode)
  step(state, a, key, task) -> (state, obs, reward, done, metric)

`metric` is the env's gate statistic (bandit: pulled best arm; catch: success,
nonzero only on terminal steps). T is lifetime length in steps.
"""
import jax
import jax.numpy as jnp



def bandit_env(n_arms=8, lifetime=200, needle=False, mix=0.0):
    """Bernoulli bandit. Default: p_i ~ U(0,1) per lifetime (forgiving —
    second-best is typically close to best, so satisficing nearly pays).
    needle=True: one arm at 0.9, the rest at 0.1 — finding the needle is
    constitutive of success; settling pays 0.1. mix=p: each lifetime is a
    needle task w.p. p, else uniform (curriculum contrast). One-step episodes."""
    assert 2 <= n_arms <= 8

    def sample_task(key):
        if needle:
            pos = jax.random.randint(key, (), 0, n_arms)
            return jnp.where(jnp.arange(n_arms) == pos, 0.9, 0.1)
        return jax.random.uniform(key, (n_arms,))

    if mix > 0:
        base = sample_task

        def sample_task(key):  # noqa: F811 — mixture wraps the base sampler
            ku, kn, kc = jax.random.split(key, 3)
            pos = jax.random.randint(kn, (), 0, n_arms)
            needle_p = jnp.where(jnp.arange(n_arms) == pos, 0.9, 0.1)
            return jnp.where(jax.random.bernoulli(kc, mix),
                             needle_p, base(ku))

    def reset(key, task):
        return (), jnp.zeros(OBS_DIM)

    def step(state, a, key, task):
        valid = a < n_arms                      # SPEC §2: surplus actions = no-op
        a_eff = jnp.where(valid, a, 0)          # safe gather index when invalid
        pull = jax.random.bernoulli(key, task[a_eff]).astype(jnp.float32)
        r = jnp.where(valid, pull, 0.0)         # a no-op earns nothing
        best = (a_eff == jnp.argmax(task)).astype(jnp.float32)
        metric = jnp.where(valid, best, 0.0)    # and never counts as best-arm
        return (), jnp.zeros(OBS_DIM), r, jnp.bool_(True), metric

    return dict(sample_task=sample_task, reset=reset, step=step,
                T=lifetime, name=f"bandit{n_arms}")


def catch_env(episodes=32):
    """bsuite-style Catch: 10x5 board, ball falls one row/step, paddle on the
    bottom row. +1 catch / -1 miss on the terminal step. 9-step episodes."""
    ROWS, COLS = 10, 5

    def _obs(state):
        ball_row, ball_col, paddle = state
        grid = jnp.zeros((ROWS, COLS))
        grid = grid.at[ball_row, ball_col].set(1.0)
        grid = grid.at[ROWS - 1, paddle].set(1.0)
        flat = grid.reshape(-1)
        return jnp.concatenate([flat, jnp.zeros(OBS_DIM - flat.shape[0])])

    def sample_task(key):
        return jnp.zeros(())  # no task variation in P0

    def reset(key, task):
        col = jax.random.randint(key, (), 0, COLS)
        state = (jnp.int32(0), col, jnp.int32(COLS // 2))
        return state, _obs(state)

    def step(state, a, key, task):
        ball_row, ball_col, paddle = state
        move = jnp.where(a == 0, -1, jnp.where(a == 2, 1, 0))  # 3..7 -> stay
        paddle = jnp.clip(paddle + move, 0, COLS - 1)
        ball_row = ball_row + 1
        done = ball_row >= ROWS - 1
        caught = (ball_col == paddle).astype(jnp.float32)
        r = jnp.where(done, 2.0 * caught - 1.0, 0.0)
        state = (ball_row, ball_col, paddle)
        return state, _obs(state), r, done, jnp.where(done, caught, 0.0)

    return dict(sample_task=sample_task, reset=reset, step=step,
                T=episodes * (ROWS - 1), name="catch")


def cbandit_env(n_arms=8, lifetime=256, C_ctx=5, frozen_rule=True, rule_seed=0,
                mix=0.0, hi_std=0.8, lo_std=0.2, hi_needle=0.95, lo_needle=0.05):
    """Contextual bandit (PREREG_P1 §1, the PRIMARY env). Each one-step trial
    draws a context c ~ U{0..C-1}; obs = onehot(c) padded to OBS_DIM. The correct
    arm is an injective map y(c): C->K (C_ctx<=n_arms). Pulling y(c) pays `hi`,
    else `lo`; the curriculum mixes a sharp "needle" margin (0.95/0.05) w.p. `mix`
    else standard (0.8/0.2). metric = pulled-correct-arm (the gate statistic).

    Two modes (PREREG_P1 B3):
      frozen_rule=True  (cbandit-FR, HEADLINE) — y is FIXED, seeded once from
        `rule_seed`, SHARED across every lifetime and eval. The only per-lifetime
        unknown is the interface (P,π) applied in rollout: the within-lifetime
        slope is pure interface-inference speed.
      frozen_rule=False (cbandit-FG, co-gated) — y resampled per lifetime ⇒
        genuine in-context task-learning under randomization.

    The env is interface-AGNOSTIC: obs-projection P and action-permutation π are
    applied by rollout/collect (B2). step() scores whatever arm it receives, so
    the metric is computed on the post-permutation arm (what was actually pulled).
    """
    assert 2 <= n_arms <= N_ACT
    assert 2 <= C_ctx <= n_arms          # injective map needs C <= K
    assert C_ctx <= OBS_DIM

    def _rule(key):
        # injective C->K: first C entries of a random arm permutation
        return jax.random.permutation(key, n_arms)[:C_ctx]

    Y_FIXED = _rule(jax.random.PRNGKey(rule_seed))   # FR closure constant

    def sample_task(key):
        ky, kn = jax.random.split(key)
        y = Y_FIXED if frozen_rule else _rule(ky)
        needle = jax.random.bernoulli(kn, mix)
        hi = jnp.where(needle, hi_needle, hi_std)
        lo = jnp.where(needle, lo_needle, lo_std)
        return dict(y=y, hi=hi, lo=lo)

    def reset(key, task):
        c = jax.random.randint(key, (), 0, C_ctx)
        obs = jnp.zeros(OBS_DIM).at[c].set(1.0)
        return c, obs

    def step(state, a, key, task):
        c = state
        valid = a < n_arms                       # SPEC §2: surplus actions = no-op
        a_eff = jnp.where(valid, a, 0)
        is_correct = jnp.logical_and(valid, a_eff == task["y"][c])
        p = jnp.where(is_correct, task["hi"], task["lo"])
        r = jnp.where(valid, jax.random.bernoulli(key, p).astype(jnp.float32), 0.0)
        metric = is_correct.astype(jnp.float32)
        # one-step episode (done every trial); rollout auto-resets a new context
        return c, jnp.zeros(OBS_DIM), r, jnp.bool_(True), metric

    return dict(sample_task=sample_task, reset=reset, step=step,
                T=lifetime, name=f"cbandit{'FR' if frozen_rule else 'FG'}")


ENVS = {"bandit": bandit_env, "catch": catch_env, "cbandit": cbandit_env}

# ===== changeling/agent.py =====
"""S1 substrate: plain GRU, pure JAX. Params are a flat dict pytree."""
import jax
import jax.numpy as jnp



def init_gru(key, hidden=128, in_dim=IN_DIM, out_dim=N_ACT):
    ks = jax.random.split(key, 7)
    s_in, s_h = 1.0 / jnp.sqrt(in_dim), 1.0 / jnp.sqrt(hidden)

    def mat(k, shape, scale):
        return jax.random.normal(k, shape) * scale

    return {
        "Wxz": mat(ks[0], (in_dim, hidden), s_in), "Whz": mat(ks[1], (hidden, hidden), s_h),
        "bz": jnp.zeros(hidden),
        "Wxr": mat(ks[2], (in_dim, hidden), s_in), "Whr": mat(ks[3], (hidden, hidden), s_h),
        "br": jnp.zeros(hidden),
        "Wxh": mat(ks[4], (in_dim, hidden), s_in), "Whh": mat(ks[5], (hidden, hidden), s_h),
        "bh": jnp.zeros(hidden),
        "Wo": mat(ks[6], (hidden, out_dim), s_h), "bo": jnp.zeros(out_dim),
    }


def gru_step(p, h, x):
    z = jax.nn.sigmoid(x @ p["Wxz"] + h @ p["Whz"] + p["bz"])
    r = jax.nn.sigmoid(x @ p["Wxr"] + h @ p["Whr"] + p["br"])
    hh = jnp.tanh(x @ p["Wxh"] + (r * h) @ p["Whh"] + p["bh"])
    h = (1.0 - z) * h + z * hh
    return h, h @ p["Wo"] + p["bo"]


def hidden_size(params):
    return params["bz"].shape[0]

# ===== changeling/looped.py =====
"""Increment A (SPEC §5b/S3-M.1): the looped core + adaptive-K micro-turns,
PonderNet-MARGINALIZED. Standalone + pure — no store, no slow bank yet.

The per-env-step computation runs K_max weight-tied micro-turns of the core over
the SAME step input x (hourglass: recurrent DEPTH over fixed context), and COMMITS
THE MARGINAL MIXTURE pi = sum_k p_k * softmax(logits_k) — never a discrete halt
sample. Marginalization is the over-determined lynchpin (PPO replay-exactness +
antithetic-CRN + teacher-forcing all force it): `micro_loop` is a deterministic
pure function of (params, h, x), so collect() and loss_fn.forward() will produce
bitwise-identical commit log-probs.

REDUCTION INVARIANT (the regression spine): at K_max=1 this collapses exactly to
`gru_step` -> log_softmax — so the whole substrate is a strict superset of today's
harness. Verified in __main__.

`make_step(cfg)` is the B1 abstract step_fn: it returns a pure
    step(params, h, x) -> (h_new, sample_score, logp_all, value, aux)
that the rollout / collect / loss_fn forward all share. cfg["loop"]=False emits the
EXACT legacy gru path (sample_score = RAW logits, so categorical draws are bitwise
identical to the pre-refactor harness — the G0-A 0.6216 regression spine); loop=True
emits the marginalized micro-loop (sample_score = logp_all = commit_logp).
"""
import jax
import jax.numpy as jnp



def init_looped(key, hidden=128):
    """GRU core (policy logits via Wo/bo) + a halting head + a value head.

    Halt head is named Whalt/bhalt (NOT bh) — the GRU already owns p["bh"] as its
    candidate-state bias; colliding on that key silently ties two unrelated params.
    """
    kg, kh, kv = jax.random.split(key, 3)
    p = init_gru(kg, hidden=hidden)  # carries Wxz..Wo/bo (incl. candidate bias bh)
    s_h = 1.0 / jnp.sqrt(hidden)
    p["Whalt"] = jax.random.normal(kh, (hidden, 1)) * s_h
    p["bhalt"] = jnp.zeros(1)
    p["Wv"] = jax.random.normal(kv, (hidden, 1)) * s_h
    p["bv"] = jnp.zeros(1)
    return p


def _ponder_p(halt_k, k_max, k_min):
    """PonderNet halting masses p_k over k=1..K_max (cumulative-product), with a
    K_min floor (no halt before k_min) and forced halt at K_max (residual mass)."""
    lam = jax.nn.sigmoid(halt_k)                       # (K,)
    lam = lam * (jnp.arange(k_max) >= (k_min - 1))     # K_min>=2 floor
    lam = lam.at[-1].set(1.0)                          # must halt by K_max -> sum p = 1
    notbefore = jnp.concatenate(                       # prod_{j<k}(1 - lam_j)
        [jnp.ones(1), jnp.cumprod(1.0 - lam)[:-1]])
    return lam * notbefore                             # (K,)


def geometric_prior(lam_p, k_max, k_min):
    """Truncated geometric prior over k=1..K_max (PonderNet KL target), zeroed
    below k_min and renormalized over the realizable support."""
    k = jnp.arange(k_max)                              # 0..K_max-1 -> k=1..K_max
    g = lam_p * (1.0 - lam_p) ** k
    g = g * (k >= (k_min - 1))                         # match the K_min floor
    return g / g.sum()


def kl_to_geometric(p, lam_p, k_max, k_min):
    """KL(p || geometric_prior). p_k=0 terms contribute 0 (PonderNet L_reg)."""
    g = geometric_prior(lam_p, k_max, k_min)
    return jnp.where(p > 0, p * (jnp.log(p + 1e-12) - jnp.log(g + 1e-12)), 0.0).sum()


def micro_loop(p, h, x, k_max=8, k_min=2):
    """One env-step's internal compute. Returns (h_new, commit_logp, commit_v, aux).
    Pure in (p, h, x): no RNG, no state outside the args -> replay-exact."""
    def turn(m, _):
        m, logits = gru_step(p, m, x)                  # weight-tied core re-reads x
        halt = (m @ p["Whalt"] + p["bhalt"])[0]
        v = (m @ p["Wv"] + p["bv"])[0]
        return m, (m, logits, halt, v)

    _, (ms, logits_k, halt_k, v_k) = jax.lax.scan(turn, h, None, length=k_max)
    # ms (K,H)  logits_k (K,A)  halt_k (K,)  v_k (K,)
    pk = _ponder_p(halt_k, k_max, k_min)               # (K,)
    probs_k = jax.nn.softmax(logits_k, axis=-1)        # (K,A)
    pi = (pk[:, None] * probs_k).sum(0)                # (A,) marginal commit dist
    commit_logp = jnp.log(pi + 1e-12)
    commit_v = (pk * v_k).sum()
    h_new = (pk[:, None] * ms).sum(0)                  # marginal committed state
    e_k = (pk * (jnp.arange(k_max) + 1.0)).sum()       # E[K]
    aux = dict(E_K=e_k, p=pk, logits_k=logits_k, v_k=v_k, halt_k=halt_k)
    return h_new, commit_logp, commit_v, aux


def make_step(cfg):
    """B1 abstract step_fn. Returns a pure
        step(params, h, x) -> (h_new, sample_score, logp_all, value, aux)
    where `sample_score` is what jax.random.categorical consumes, `logp_all` is the
    (A,) action log-prob vector (for stored logp / entropy / the PPO ratio), `value`
    is the committed state-value (commit_v) for the looped path or None for legacy
    (PPO computes the legacy value from its own top-level head), and `aux` always
    carries E_K.

    loop=False is byte-identical to the legacy harness: sample_score = RAW gru
    logits, so categorical(key, sample_score) draws the same action bit-for-bit."""
    if not cfg.get("loop", False):
        def step(params, h, x):
            h2, logits = gru_step(params, h, x)
            return h2, logits, jax.nn.log_softmax(logits), None, {
                "E_K": jnp.float32(1.0)}
        return step

    k_max = int(cfg["k_max"])
    k_min = int(cfg.get("k_min", 2))

    def step(params, h, x):
        h2, clp, cv, aux = micro_loop(params, h, x, k_max=k_max, k_min=k_min)
        return h2, clp, clp, cv, aux
    return step


